/**
 * @param {Function} fn
 * @param {number} delay
 * @returns {Function}
 */
function debounce(fn, delay) {
  // Your code here
}

questions.solutionCode:
function debounce(fn, delay) {
  let timerId;
  return function (...args) {
    const ctx = this;
    clearTimeout(timerId);
    timerId = setTimeout(() => fn.apply(ctx, args), delay);
  };
}

