/**
 * @param {Array<number|number[]>} arr
 * @returns {number[]}
 */
function flattenOnce(arr) {
  // Your code here
}

questions.solutionCode:
function flattenOnce(arr) {
  const out = [];
  for (const x of arr) {
    if (Array.isArray(x)) out.push(...x);
    else out.push(x);
  }
  return out;
}
